                <span style={{ position:'absolute', top:12, left:12, background:'rgba(20,16,12,.62)', color:'#fff', fontSize:12, fontWeight:600, borderRadius:999, padding:'5px 12px', backdropFilter:'blur(4px)' }}>From {fmt(t.from)}</span>
